FreeGiftConfig = {}
FreeGiftConfig.freeGift = {}

function FreeGiftConfig:init(giftConfig)
    for _, config in pairs(giftConfig) do
        local data = {}
        data.Id = tonumber(config.GiftId)
        data.RewardId = tonumber(config.RewardId)
        data.CD = tonumber(config.CD)
        data.Times = tonumber(config.Times)
        table.insert(self.freeGift, data)
    end


    table.sort(self.freeGift, function(a,b)
        return a.Id < b.Id
    end)
end

function FreeGiftConfig:getGifts()
    return self.freeGift
end

function FreeGiftConfig:getGiftById(id)
    for _, gift in pairs(self.freeGift) do
        if gift.Id == id then
            return gift
        end
    end
end

function FreeGiftConfig:getGiftByRewardId(rewardId)
    for _, gift in pairs(self.freeGift) do
        if gift.RewardId == rewardId then
            return gift
        end
    end
end